class Solution {
    public int largestInteger(int num) {
        int result = num;
        while (true) {
            if (isEven(result)) {
                int temp = result % 10;
                result /= 10;
                result *= 10;
                result += temp;
            } else {
                int temp = result % 10;
                result /= 10;
                result *= 10;
                result -= temp;
            }
            if (result == 0) {
                break;
            }
        }
        return result;
    }

    private boolean isEven(int num) {
        return num % 2 == 0;
    }
}
```

